120	// Combined parse function avoids mutual recursion.
121	// mode 0 = expression, mode 1 = value only
122	int parse_node(int mode);
123	
124	int parse_node(int mode) {
125	    if (parse_err) return 0;
126	
127	    int left;
128	    int ty = tok_type[parse_pos];
129	
130	    // -- Parse a value --
131	
132	    if (ty == TOK_NUM) {
133	        left = ast_num(tok_val[parse_pos]);
134	        parse_pos++;
135	
136	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
137	        if (tok_type[parse_pos] == TOK_NUM) {
138	            strand_buf[0] = node_val[left];
139	            int count = 1;
140	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
141	                strand_buf[count] = tok_val[parse_pos];
142	                parse_pos++;
143	                count++;
144	            }
145	            int aidx = arr_vector(count);
146	            if (aidx < 0) { parse_err = 1; return 0; }
147	            int si = 0;
148	            while (si < count) {
149	                arr_set(aidx, si, strand_buf[si]);
150	                si++;
151	            }
152	            left = ast_vec(aidx);
153	        }
154	    } else if (ty == TOK_LPAREN) {
155	        parse_pos++;
156	        left = parse_node(0);
157	        if (parse_err) return 0;
158	        if (tok_type[parse_pos] != TOK_RPAREN) {
159	            parse_err = 1;
160	            return 0;
161	        }
162	        parse_pos++;
163	    } else if (ty == TOK_IDENT) {
164	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
165	        if (sym_idx < 0) { parse_err = 1; return 0; }
166	        left = ast_ident(sym_idx);
167	        parse_pos++;
168	    } else if (ty == TOK_RES) {
169	        // Monadic primitive function (e.g. iota expr)
170	        int res_id = tok_val[parse_pos];
171	        parse_pos++;
172	        int operand = parse_node(0);
173	        if (parse_err) return 0;
174	        left = ast_monad(res_id, operand);
175	    } else if (ty == TOK_MINUS) {
176	        // Monadic negate: applies to entire right expression (APL rule)
177	        parse_pos++;
178	        int operand = parse_node(0);
179	        if (parse_err) return 0;
180	        left = ast_neg(operand);
181	    } else {
182	        parse_err = 1;
183	        return 0;
184	    }
185	
186	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
187	
188	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
189	        int op = tok_type[parse_pos];
190	        parse_pos++;
191	        int right = parse_node(0);
192	        if (parse_err) return 0;
193	        return ast_binop(op, left, right);
194	    }
195	
196	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
197	        int res_id = tok_val[parse_pos];
198	        parse_pos++;
199	        int right = parse_node(0);
200	        if (parse_err) return 0;
201	        return ast_dyad(res_id, left, right);
202	    }
203	
204	    return left;
205	}
206	
207	// Parse the token stream. Returns root node index, or -1 on error.
208	// line is needed for identifier name resolution into the symbol table.
209	int parse(char *line) {
210	    node_count = 0;
211	    parse_pos = 0;
212	    parse_err = 0;
213	    parse_line = line;
214	
215	    // Check for assignment: IDENT <- expr
216	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
217	        int sym_idx = sym_lookup(line, tok_val[0]);
218	        if (sym_idx < 0) { return -1; }
219	        parse_pos = 2;
220	        int expr = parse_node(0);
221	        if (parse_err) return -1;
222	        if (tok_type[parse_pos] != TOK_EOL) return -1;
223	        return ast_assign(sym_idx, expr);
224	    }
225	
226	    int root = parse_node(0);
227	
228	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
229	        parse_err = 1;
230	    }
231	
232	    if (parse_err) return -1;
233	    return root;
234	}
235	
236	// Debug: dump AST with full parenthesization
237	void ast_dump(int n) {
238	    if (n < 0 || n >= node_count) return;
239	
240	    int ty = node_type[n];
241	    if (ty == NODE_NUM) {
242	        print_int(node_val[n]);
243	    } else if (ty == NODE_BINOP) {
244	        putchar(40);
245	        ast_dump(node_left[n]);
246	        putchar(32);
247	        if (node_val[n] == TOK_PLUS)  putchar(43);
248	        if (node_val[n] == TOK_MINUS) putchar(45);
249	        if (node_val[n] == TOK_STAR)  putchar(42);
250	        if (node_val[n] == TOK_SLASH) putchar(47);
251	        putchar(32);
252	        ast_dump(node_right[n]);
253	        putchar(41);
254	    } else if (ty == NODE_NEG) {
255	        putchar(40);
256	        putchar(45);
257	        ast_dump(node_right[n]);
258	        putchar(41);
259	    }
260	}
