1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH
9	int eval_err;
10	
11	// Apply a binary op to two scalars
12	int eval_binop_scalar(int op, int a, int b) {
13	    if (op == TOK_PLUS)       return a + b;
14	    if (op == TOK_MINUS)      return a - b;
15	    if (op == TOK_STAR)       return a * b;
16	    if (op == TOK_SLASH) {
17	        if (b == 0) { eval_err = 1; return 0; }
18	        return a / b;
19	    }
20	    eval_err = 1;
21	    return 0;
22	}
23	
24	// Evaluate AST node, return heap index of result array.
25	// On error, sets eval_err and returns -1.
26	int eval(int n) {
27	    if (eval_err) return -1;
28	    if (n < 0 || n >= node_count) {
29	        eval_err = 1;
30	        return -1;
31	    }
32	
33	    int ty = node_type[n];
34	
35	    if (ty == NODE_NUM) {
36	        int r = arr_scalar(node_val[n]);
37	        if (r < 0) { eval_err = 1; return -1; }
38	        return r;
39	    }
40	
41	    if (ty == NODE_VEC) {
42	        return node_val[n];
43	    }
44	
45	    if (ty == NODE_IDENT) {
46	        int idx = node_val[n];
47	        if (!sym_set_flag[idx]) {
48	            eval_err = 2;
49	            return -1;
50	        }
51	        return sym_val[idx];
52	    }
53	
54	    if (ty == NODE_ASSIGN) {
55	        int idx = node_val[n];
56	        int v = eval(node_right[n]);
57	        if (eval_err) return -1;
58	        sym_val[idx] = v;
59	        sym_set_flag[idx] = 1;
60	        return v;
61	    }
62	
63	    if (ty == NODE_NEG) {
64	        int v = eval(node_right[n]);
65	        if (eval_err) return -1;
66	        int rk = arr_rank(v);
67	        if (rk == 0) {
68	            int r = arr_scalar(0 - arr_get(v, 0));
69	            if (r < 0) { eval_err = 1; return -1; }
70	            return r;
71	        }
72	        // Negate each element of vector
73	        int sz = arr_size(v);
74	        int r = arr_vector(sz);
75	        if (r < 0) { eval_err = 1; return -1; }
76	        int i = 0;
77	        while (i < sz) {
78	            arr_set(r, i, 0 - arr_get(v, i));
79	            i++;
80	        }
81	        return r;
82	    }
83	
84	    if (ty == NODE_MONAD) {
85	        int v = eval(node_right[n]);
86	        if (eval_err) return -1;
87	        int res_id = node_val[n];
88	
89	        if (res_id == RES_IOTA) {
90	            // iota N: generate vector 0 1 2 ... N-1
91	            if (arr_rank(v) != 0) { eval_err = 3; return -1; }
92	            int count = arr_get(v, 0);
93	            if (count < 0) { eval_err = 1; return -1; }
94	            int r = arr_vector(count);
95	            if (r < 0) { eval_err = 1; return -1; }
96	            int i = 0;
97	            while (i < count) {
98	                arr_set(r, i, i);
99	                i++;
100	            }
101	            return r;
102	        }
103	
104	        if (res_id == RES_RHO) {
105	            // rho A: return shape of A
106	            int rk = arr_rank(v);
107	            if (rk == 0) {
108	                // Scalar: shape is empty vector
109	                int r = arr_vector(0);
110	                if (r < 0) { eval_err = 1; return -1; }
111	                return r;
112	            }
113	            if (rk == 1) {
114	                // Vector: shape is 1-element vector with length
115	                int r = arr_scalar(arr_dim0(v));
116	                if (r < 0) { eval_err = 1; return -1; }
117	                return r;
118	            }
119	            if (rk == 2) {
120	                // Matrix: shape is 2-element vector (rows cols)
121	                int r = arr_vector(2);
122	                if (r < 0) { eval_err = 1; return -1; }
123	                arr_set(r, 0, arr_dim0(v));
124	                arr_set(r, 1, arr_dim1(v));
125	                return r;
126	            }
127	            eval_err = 1;
128	            return -1;
129	        }
130	
131	        // Unknown monadic function
132	        eval_err = 1;
133	        return -1;
134	    }
135	
136	    if (ty == NODE_DYAD) {
137	        int lv = eval(node_left[n]);
138	        if (eval_err) return -1;
139	        int rv = eval(node_right[n]);
140	        if (eval_err) return -1;
141	        int res_id = node_val[n];
142	
143	        if (res_id == RES_RHO) {
144	            // S rho A: reshape A to shape S with cyclic fill
145	            // S is scalar -> result is vector of that length
146	            // S is 2-element vector -> result is matrix
147	            int lrk = arr_rank(lv);
148	            int new_rank;
149	            int d0;
150	            int d1;
151	
152	            if (lrk == 0) {
153	                // Scalar shape -> vector
154	                new_rank = 1;
155	                d0 = arr_get(lv, 0);
156	                d1 = 0;
157	                if (d0 < 0) { eval_err = 1; return -1; }
158	            } else if (lrk == 1) {
159	                int lsz = arr_size(lv);
160	                if (lsz == 1) {
161	                    new_rank = 1;
